  React.ComponentPropsWithoutRef<typeof TogglePrimitive.Root> & VariantProps<typeof toggleVariants>
>(({ className, variant, size, ...props }, ref) => (
  <TogglePrimitive.Root ref={ref} className={cn(toggleVariants({ variant, size, className }))} {...props} />
));

Toggle.displayName = TogglePrimitive.Root.displayName;

export { Toggle, toggleVariants };

export interface PaymentRecord {
  id: string;
  amount: number;
  currency: string;
  status: "success" | "failed" | "dismissed";
  createdAt: number;
}

const KEY = "paymentHistory";

export function getPayments(): PaymentRecord[] {
  try {
    const raw = localStorage.getItem(KEY);
    if (!raw) return [];
    const parsed = JSON.parse(raw);
    if (Array.isArray(parsed)) return parsed as PaymentRecord[];
    return [];
  } catch {
    return [];
  }
}

export function addPayment(rec: PaymentRecord) {
  try {
    const list = getPayments();
    list.unshift(rec);
    localStorage.setItem(KEY, JSON.stringify(list.slice(0, 100)));
  } catch {}
}

const RAW_RAZORPAY_KEY_ID = import.meta.env.VITE_RAZORPAY_KEY_ID as string | undefined;
const RAZORPAY_KEY_ID = (RAW_RAZORPAY_KEY_ID ?? "").trim() || undefined;

export interface OpenProCheckoutParams {
  amountInRupees?: number;
  customerName?: string;
  customerEmail?: string;
  customerPhone?: string;
}

declare global {
  interface Window {
    Razorpay?: new (options: any) => {
      open: () => void;
      close: () => void;
      on: (event: string, callback: (data: any) => void) => void;
    };
  }
}

function loadRazorpayScript(): Promise<boolean> {
  return new Promise((resolve) => {
    if (document.querySelector('script[src="https://checkout.razorpay.com/v1/checkout.js"]')) {
      resolve(true);
      return;
    }

    const script = document.createElement("script");
    script.src = "https://checkout.razorpay.com/v1/checkout.js";
    script.async = true;
    script.onload = () => resolve(true);
    script.onerror = () => resolve(false);
    document.body.appendChild(script);
  });
}

import { addPayment } from "@/lib/payments";

export async function openProCheckout(params: OpenProCheckoutParams = {}) {
  const ok = await loadRazorpayScript();

  if (!ok || !window.Razorpay) {
    console.error("Razorpay SDK failed to load.");
    return;
  }

  if (!RAZORPAY_KEY_ID) {
    console.error("VITE_RAZORPAY_KEY_ID is not set in .env.local");
    return;
  }

  const amountInRupees = params.amountInRupees ?? 499;
  const amountInPaise = Math.round(amountInRupees * 100);

  let orderId: string | undefined = undefined;

  const options = {
    key: RAZORPAY_KEY_ID,
    amount: amountInPaise,
    currency: "INR",
    name: "AutoCaption AI",
    description: "Pro Plan Subscription",
    order_id: orderId,
    redirect: false,
    retry: {
      enabled: true,
      max_count: 1,
    },
    notes: {
      plan: "pro_monthly",
      platform: "web_app",
    },
    prefill: {
      name: params.customerName ?? "",
      email: params.customerEmail ?? "",
      contact: params.customerPhone ?? "",
    },
    theme: {
      color: "#6366F1",
    },
    handler: (response: any) => {
      try {
        const paymentId =
          response?.razorpay_payment_id || response?.payment_id || `test_${Date.now()}`;
        addPayment({
          id: paymentId,
          amount: amountInPaise / 100,
          currency: "INR",
          status: "success",
          createdAt: Date.now(),
        });
      } catch {}
      try {
        window.location.assign("/dashboard");
      } catch {}
    },
    modal: {
      ondismiss: () => {
        try {
          addPayment({
            id: `dismissed_${Date.now()}`,
            amount: amountInPaise / 100,
            currency: "INR",
            status: "dismissed",
            createdAt: Date.now(),
          });
        } catch {}
      },
    },
  };

  try {
    delete (options as any).order_id;
    const rzp = new window.Razorpay!(options);
    rzp.open();
  } catch (e) {
    console.error("Failed to open Razorpay checkout:", e);
  }
}

import { ensureSupabase } from "@/lib/supabase";

export function getSyncUserId(): string {
  try {
    for (let i = 0; i < localStorage.length; i++) {
      const key = localStorage.key(i);
      if (key && key.startsWith('sb-') && key.endsWith('-auth-token')) {
        const token = localStorage.getItem(key);
        if (token) {
          const parsed = JSON.parse(token);
          if (parsed?.user?.id) {
            return parsed.user.id;
          }
        }
      }
    }
  } catch {}
  return 'guest';
}

const getUsageKey = () => `freeGenerationsCount_${getSyncUserId()}`;

export function getFreeGenerationsRemaining() {
  try {
    const count = parseInt(localStorage.getItem(getUsageKey()) || "0", 10);
    return Math.max(0, 5 - count);
  } catch {
    return 5;
  }
}

export function hasUsedFree() {
  return getFreeGenerationsRemaining() <= 0;
}

export function markFreeUsed() {
  try {
    const key = getUsageKey();
    const count = parseInt(localStorage.getItem(key) || "0", 10);
    localStorage.setItem(key, (count + 1).toString());
  } catch {}
}

export async function isLoggedIn() {
  try {
    const supabase = ensureSupabase();
    const { data } = await supabase.auth.getSession();
    return !!data.session;
  } catch {
    return false;
  }
}

